select system_id, system_name, system_info, use_flag
  from cotdl.tbl_piisystem 
 where system_id= #{system_id, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_piisystem
   set 
		system_name= #{system_name, jdbcType=VARCHAR},
		system_info= #{system_info, jdbcType=VARCHAR},
		use_flag= #{use_flag, jdbcType=VARCHAR}
 where system_id= #{system_id, jdbcType=VARCHAR}

mapper.select:
 
		 
		select 
			system_id, system_name, system_info, use_flag 
		from ( 
				select 
					 ROWNUM rn, system_id, system_name, system_info, use_flag 
				from (
						select system_id, system_name, system, env, dbtype, dbuser, pwd, hostname, port, sid, servicename, comments, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduseri
						  from cotdl.tbl_piisystem order by system_id
					 ) a
				where 
		
	    
		
						
							and upper(system_id) like '%'||upper(#{search1})||'%'
						
						
							and system_name like '%'||#{search2}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by system_id
			  ) b
		where rn > (#{pagenum} -1) * #{amount} 
		order by system_id
